#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    int sum = 0;
    for (int i = 0; i < N; i++) {
        for (int j = i + 1; j < N; j++) {
            int maxVal = A[i];
            for (int k = i; k <= j; k++) {
                if (A[k] > maxVal) {
                    maxVal = A[k];
                }
            }
            int f = ((A[i] & A[j]) == A[i]) || ((A[i] & A[j]) == A[j]);
            sum += maxVal * f;
        }
    }
    printf("%d\n", sum);
    return 0;
}

