import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
        }
        int sum = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                int maxVal = A[i];
                for (int k = i; k <= j; k++) {
                    if (A[k] > maxVal) {
                        maxVal = A[k];
                    }
                }
                int f = ((A[i] & A[j]) == A[i]) || ((A[i] & A[j]) == A[j]) ? 1 : 0;
                sum += maxVal * f;
            }
        }
        System.out.println(sum);
    }
}

