const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const N = parseInt(readline());
const A = readline().split(' ').map(x => parseInt(x));
let sum = 0;
for (let i = 0; i < N; i++) {
    for (let j = i + 1; j < N; j++) {
        let maxVal = Math.max(...A.slice(i, j + 1));
        let f = (A[i] & A[j]) === A[i] || (A[i] & A[j]) === A[j];
        sum += maxVal * f;
    }
}
